    "content": "{"content":"}\n\nvm_fault_t filemap_map_pages(struct vm_fault *vmf,\n\t\t\t     pgoff_t start_pgoff, pgoff_t end_pgoff)\n{\n\tstruct vm_area_struct *vma = vmf->vma;\n\tstruct file *file = vma->vm_file;\n\tstruct address_space *mapping = file->f_mapping;\n\tpgoff_t file_end, last_pgoff = start_pgoff;\n\tunsigned long addr;\n\tXA_STATE(xas, &mapping->i_pages, start_pgoff);\n\tstruct folio *folio;\n\tvm_fault_t ret = 0;\n\tunsigned long rss = 0;\n\tunsigned int nr_pages = 0, folio_type;\n\tunsigned short mmap_miss = 0, mmap_miss_saved;\n\n\t/*\n\t * Recalculate end_pgoff based on file_end before calling\n\t * next_uptodate_folio() to avoid races with concurrent\n\t * truncation.\n\t */\n\tfile_end = DIV_ROUND_UP(i_size_read(mapping->host), PAGE_SIZE) - 1;\n\tend_pgoff = min(end_pgoff, file_end);\n\n\trcu_read_lock();\n\tfolio = next_uptodate_folio(&xas, mapping, end_pgoff);\n\tif (!folio)\n\t\tgoto out;\n\n\t/*\n\t * Do not allow to map with PMD across i_size to preserve\n\t * SIGBUS semantics.\n\t *\n\t * Make an exception for shmem/tmpfs that for long time\n\t * intentionally mapped with PMDs across i_size.\n\t */\n\tif ((file_end >= folio_next_index(folio) || shmem_mapping(mapping)) &&\n\t    filemap_map_pmd(vmf, folio, start_pgoff)) {\n\t\tret = VM_FAULT_NOPAGE;\n\t\tgoto out;\n\t}\n\n\taddr = vma->vm_start + ((start_pgoff - vma->vm_pgoff) << PAGE_SHIFT);\n\tvmf->pte = pte_offset_map_lock(vma->vm_mm, vmf->pmd, addr, &vmf->ptl);\n\tif (!vmf->pte) {\n\t\tfolio_unlock(folio);\n\t\tfolio_put(folio);\n\t\tgoto out;\n\t}\n\n\tfolio_type = mm_counter_file(folio);\n\tdo {\n\t\tunsigned long end;\n\n\t\taddr += (xas.xa_index - last_pgoff) << PAGE_SHIFT;\n\t\tvmf->pte += xas.xa_index - last_pgoff;\n\t\tlast_pgoff = xas.xa_index;\n\t\tend = folio_next_index(folio) - 1;\n\t\tnr_pages = min(end, end_pgoff) - xas.xa_index + 1;\n\n\t\tif (!folio_test_large(folio))\n\t\t\tret |= filemap_map_order0_folio(vmf,\n\t\t\t\t\tfolio, addr, &rss, &mmap_miss);\n\t\telse\n\t\t\tret |= filemap_map_folio_range(vmf, folio,\n\t\t\t\t\txas.xa_index - folio->index, addr,\n\t\t\t\t\tnr_pages, &rss, &mmap_miss, file_end);\n\n\t\tfolio_unlock(folio);\n\t} while ((folio = next_uptodate_folio(&xas, mapping, end_pgoff)) != NULL);\n\tadd_mm_counter(vma->vm_mm, folio_type, rss);\n\tpte_unmap_unlock(vmf->pte, vmf->ptl);\n\ttrace_mm_filemap_map_pages(mapping, start_pgoff, end_pgoff);\nout:\n\trcu_read_unlock();\n\n\tmmap_miss_saved = READ_ONCE(file->f_ra.mmap_miss);\n\tif (mmap_miss >= mmap_miss_saved)\n\t\tWRITE_ONCE(file->f_ra.mmap_miss, 0);\n\telse\n\t\tWRITE_ONCE(file->f_ra.mmap_miss, mmap_miss_saved - mmap_miss);\n\n\treturn ret;\n}\nEXPORT_SYMBOL(filemap_map_pages);\n\nvm_fault_t filemap_page_mkwrite(struct vm_fault *vmf)\n{\n\tstruct address_space *mapping = vmf->vma->vm_file->f_mapping;\n\tstruct folio *folio = page_folio(vmf->page);\n\tvm_fault_t ret = VM_FAULT_LOCKED;\n\n\tsb_start_pagefault(mapping->host->i_sb);\n\tfile_update_time(vmf->vma->vm_file);\n\tfolio_lock(folio);\n\tif (folio->mapping != mapping) {\n\t\tfolio_unlock(folio);\n\t\tret = VM_FAULT_NOPAGE;\n\t\tgoto out;\n\t}\n\t/*\n\t * We mark the folio dirty already here so that when freeze is in\n\t * progress, we are guaranteed that writeback during freezing will\n\t * see the dirty folio and writeprotect it again.\n\t */\n\tfolio_mark_dirty(folio);\n\tfolio_wait_stable(folio);\nout:\n\tsb_end_pagefault(mapping->host->i_sb);\n\treturn ret;\n}\n\nconst struct vm_operations_struct generic_file_vm_ops = {\n\t.fault\t\t= filemap_fault,\n\t.map_pages\t= filemap_map_pages,\n\t.page_mkwrite\t= filemap_page_mkwrite,\n};\n\n/* This is used for a general mmap of a disk file */\n\nint generic_file_mmap(struct file *file, struct vm_area_struct *vma)\n{\n\tstruct address_space *mapping = file->f_mapping;\n\n\tif (!mapping->a_ops->read_folio)\n\t\treturn -ENOEXEC;\n\tfile_accessed(file);\n\tvma->vm_ops = &generic_file_vm_ops;\n\treturn 0;\n}\n\nint generic_file_mmap_prepare(struct vm_area_desc *desc)\n{\n\tstruct file *file = desc->file;\n\tstruct address_space *mapping = file->f_mapping;\n\n\tif (!mapping->a_ops->read_folio)\n\t\treturn -ENOEXEC;\n\tfile_accessed(file);\n\tdesc->vm_ops = &generic_file_vm_ops;\n\treturn 0;\n}\n\n/*\n * This is for filesystems which do not implement ->writepage.\n */\nint generic_file_readonly_mmap(struct file *file, struct vm_area_struct *vma)\n{\n\tif (vma_is_shared_maywrite(vma))\n\t\treturn -EINVAL;\n\treturn generic_file_mmap(file, vma);\n}\n\nint generic_file_readonly_mmap_prepare(struct vm_area_desc *desc)\n{\n\tif (is_shared_maywrite(&desc->vma_flags))\n\t\treturn -EINVAL;\n\treturn generic_file_mmap_prepare(desc);\n}\n#else\nvm_fault_t filemap_page_mkwrite(struct vm_fault *vmf)\n{\n\treturn VM_FAULT_SIGBUS;\n}\nint generic_file_mmap(struct file *file, struct vm_area_struct *vma)\n{\n\treturn -ENOSYS;\n}\nint generic_file_mmap_prepare(struct vm_area_desc *desc)\n{\n\treturn -ENOSYS;\n}\nint generic_file_readonly_mmap(struct file *file, struct vm_area_struct *vma)\n{\n\treturn -ENOSYS;\n}\nint generic_file_readonly_mmap_prepare(struct vm_area_desc *desc)\n{\n\treturn -ENOSYS;\n}\n#endif /* CONFIG_MMU */\n\nEXPORT_SYMBOL(filemap_page_mkwrite);\nEXPORT_SYMBOL(generic_file_mmap);\nEXPORT_SYMBOL(generic_file_mmap_prepare);\nEXPORT_SYMBOL(generic_file_readonly_mmap);\nEXPORT_SYMBOL(generic_file_readonly_mmap_prepare);\n\nstatic struct folio *do_read_cache_folio(struct address_space *mapping,\n\t\tpgoff_t index, filler_t filler, struct file *file, gfp_t gfp)\n{\n\tstruct folio *folio;\n\tint err;\n\n\tif (!filler)\n\t\tfiller = mapping->a_ops->read_folio;\nrepeat:\n\tfolio = filemap_get_folio(mapping, index);\n\tif (IS_ERR(folio)) {\n\t\tfolio = filemap_alloc_folio(gfp, mapping_min_folio_order(mapping), NULL);\n\t\tif (!folio)\n\t\t\treturn ERR_PTR(-ENOMEM);\n\t\tindex = mapping_align_index(mapping, index);\n\t\terr = filemap_add_folio(mapping, folio, index, gfp);\n\t\tif (unlikely(err)) {\n\t\t\tfolio_put(folio);\n\t\t\tif (err == -EEXIST)\n\t\t\t\tgoto repeat;\n\t\t\t/* Presumably ENOMEM for xarray node */\n\t\t\treturn ERR_PTR(err);\n\t\t}\n\n\t\tgoto filler;\n\t}\n\tif (folio_test_uptodate(folio))\n\t\tgoto out;\n\n\tif (!folio_trylock(folio)) {\n\t\tfolio_put_wait_locked(folio, TASK_UNINTERRUPTIBLE);\n\t\tgoto repeat;\n\t}\n\n\t/* Folio was truncated from mapping */\n\tif (!folio->mapping) {\n\t\tfolio_unlock(folio);\n\t\tfolio_put(folio);\n\t\tgoto repeat;\n\t}\n\n\t/* Someone else locked and filled the page in a very small window */\n\tif (folio_test_uptodate(folio)) {\n\t\tfolio_unlock(folio);\n\t\tgoto out;\n\t}\n\nfiller:\n\terr = filemap_read_folio(file, filler, folio);\n\tif (err) {\n\t\tfolio_put(folio);\n\t\tif (err == AOP_TRUNCATED_PAGE)\n\t\t\tgoto repeat;\n\t\treturn ERR_PTR(err);\n\t}\n\nout:\n\tfolio_mark_accessed(folio);\n\treturn folio;\n}\n\n/**\n * read_cache_folio - Read into page cache, fill it if needed.\n * @mapping: The address_space to read from.\n * @index: The index to read.\n * @filler: Function to perform the read, or NULL to use aops->read_folio().\n * @file: Passed to filler function, may be NULL if not required.\n *\n * Read one page into the page cache.  If it succeeds, the folio returned\n * will contain @index, but it may not be the first page of the folio.\n *\n * If the filler function returns an error, it will be returned to the\n * caller.\n *\n * Context: May sleep.  Expects mapping->invalidate_lock to be held.\n * Return: An uptodate folio on success, ERR_PTR() on failure.\n */\nstruct folio *read_cache_folio(struct address_space *mapping, pgoff_t index,\n\t\tfiller_t filler, struct file *file)\n{\n\treturn do_read_cache_folio(mapping, index, filler, file,\n\t\t\tmapping_gfp_mask(mapping));\n}\nEXPORT_SYMBOL(read_cache_folio);\n\n/**\n * mapping_read_folio_gfp - Read into page cache, using specified allocation flags.\n * @mapping:\tThe address_space for the folio.\n * @index:\tThe index that the allocated folio will contain.\n * @gfp:\tThe page allocator flags to use if allocating.\n *\n * This is the same as \"read_cache_folio(mapping, index, NULL, NULL)\", but with\n * any new memory allocations done using the specified allocation flags.\n *\n * The most likely error from this function is EIO, but ENOMEM is\n * possible and so is EINTR.  If ->read_folio returns another error,\n * that will be returned to the caller.\n *\n * The function expects mapping->invalidate_lock to be already held.\n *\n * Return: Uptodate folio on success, ERR_PTR() on failure.\n */\nstruct folio *mapping_read_folio_gfp(struct address_space *mapping,\n\t\tpgoff_t index, gfp_t gfp)\n{\n\treturn do_read_cache_folio(mapping, index, NULL, NULL, gfp);\n}\nEXPORT_SYMBOL(mapping_read_folio_gfp);\n\nstatic struct page *do_read_cache_page(struct address_space *mapping,\n\t\tpgoff_t index, filler_t *filler, struct file *file, gfp_t gfp)\n{\n\tstruct folio *folio;\n\n\tfolio = do_read_cache_folio(mapping, index, filler, file, gfp);\n\tif (IS_ERR(folio))\n\t\treturn &folio->page;\n\treturn folio_file_page(folio, index);\n}\n\nstruct page *read_cache_page(struct address_space *mapping,\n\t\t\tpgoff_t index, filler_t *filler, struct file *file)\n{\n\treturn do_read_cache_page(mapping, index, filler, file,\n\t\t\tmapping_gfp_mask(mapping));\n}\nEXPORT_SYMBOL(read_cache_page);\n\n/**\n * read_cache_page_gfp - read into page cache, using specified page allocation flags.\n * @mapping:\tthe page's address_space\n * @index:\tthe page index\n * @gfp:\tthe page allocator flags to use if allocating\n *\n * This is the same as \"read_mapping_page(mapping, index, NULL)\", but with\n * any new page allocations done using the specified allocation flags.\n *\n * If the page does not get brought uptodate, return -EIO.\n *\n * The function expects mapping->invalidate_lock to be already held.\n *\n * Return: up to date page on success, ERR_PTR() on failure.\n */\nstruct page *read_cache_page_gfp(struct address_space *mapping,\n\t\t\t\tpgoff_t index,\n\t\t\t\tgfp_t gfp)\n{\n\treturn do_read_cache_page(mapping, index, NULL, NULL, gfp);\n}\nEXPORT_SYMBOL(read_cache_page_gfp);\n\n/*\n * Warn about a page cache invalidation failure during a direct I/O write.\n */\nstatic void dio_warn_stale_pagecache(struct file *filp)\n{\n\tstatic DEFINE_RATELIMIT_STATE(_rs, 86400 * HZ, DEFAULT_RATELIMIT_BURST);\n\tchar pathname[128];\n\tchar *path;\n\n\terrseq_set(&filp->f_mapping->wb_err, -EIO);\n\tif (__ratelimit(&_rs)) {\n\t\tpath = file_path(filp, pathname, sizeof(pathname));\n\t\tif (IS_ERR(path))\n\t\t\tpath = \"(unknown)\";\n\t\tpr_crit(\"Page cache invalidation failure on direct I/O.  Possible data corruption due to collision with buffered I/O!\\n\");\n\t\tpr_crit(\"File: %s PID: %d Comm: %.20s\\n\", path, current->pid,\n\t\t\tcurrent->comm);\n\t}\n}\n\nvoid kiocb_invalidate_post_direct_write(struct kiocb *iocb, size_t count)\n{\n\tstruct address_space *mapping = iocb->ki_filp->f_mapping;\n\n\tif (mapping->nrpages &&\n\t    invalidate_inode_pages2_range(mapping,\n\t\t\tiocb->ki_pos >> PAGE_SHIFT,\n\t\t\t(iocb->ki_pos + count - 1) >> PAGE_SHIFT))\n\t\tdio_warn_stale_pagecache(iocb->ki_filp);\n}\n\nssize_t\ngeneric_file_direct_write(struct kiocb *iocb, struct iov_iter *from)\n{\n\tstruct address_space *mapping = iocb->ki_filp->f_mapping;\n\tsize_t write_len = iov_iter_count(from);\n\tssize_t written;\n\n\t/*\n\t * If a page can not be invalidated, return 0 to fall back\n\t * to buffered write.\n\t */\n\twritten = kiocb_invalidate_pages(iocb, write_len);\n\tif (written) {\n\t\tif (written == -EBUSY)\n\t\t\treturn 0;\n\t\treturn written;\n\t}\n\n\twritten = mapping->a_ops->direct_IO(iocb, from);\n\n\t/*\n\t * Finally, try again to invalidate clean pages which might have been\n\t * cached by non-direct readahead, or faulted in by get_user_pages()\n\t * if the source of the write was an mmap'ed region of the file\n\t * we're writing.  Either one is a pretty crazy thing to do,\n\t * so we don't support it 100%.  If this invalidation\n\t * fails, tough, the write still worked...\n\t *\n\t * Most of the time we do not need this since dio_complete() will do\n\t * the invalidation for us. However there are some file systems that\n\t * do not end up with dio_complete() being called, so let's not break\n\t * them by removing it completely.\n\t *\n\t * Noticeable example is a blkdev_direct_IO().\n\t *\n\t * Skip invalidation for async writes or if mapping has no pages.\n\t */\n\tif (written > 0) {\n\t\tstruct inode *inode = mapping->host;\n\t\tloff_t pos = iocb->ki_pos;\n\n\t\tkiocb_invalidate_post_direct_write(iocb, written);\n\t\tpos += written;\n\t\twrite_len -= written;\n\t\tif (pos > i_size_read(inode) && !S_ISBLK(inode->i_mode)) {\n\t\t\ti_size_write(inode, pos);\n\t\t\tmark_inode_dirty(inode);\n\t\t}\n\t\tiocb->ki_pos = pos;\n\t}\n\tif (written != -EIOCBQUEUED)\n\t\tiov_iter_revert(from, write_len - iov_iter_count(from));\n\treturn written;\n}\nEXPORT_SYMBOL(generic_file_direct_write);\n\nssize_t generic_perform_write(struct kiocb *iocb, struct iov_iter *i)\n{\n\tstruct file *file = iocb->ki_filp;\n\tloff_t pos = iocb->ki_pos;\n\tstruct address_space *mapping = file->f_mapping;\n\tconst struct address_space_operations *a_ops = mapping->a_ops;\n\tsize_t chunk = mapping_max_folio_size(mapping);\n\tlong status = 0;\n\tssize_t written = 0;\n\n\tdo {\n\t\tstruct folio *folio;\n\t\tsize_t offset;\t\t/* Offset into folio */\n\t\tsize_t bytes;\t\t/* Bytes to write to folio */\n\t\tsize_t copied;\t\t/* Bytes copied from user */\n\t\tvoid *fsdata = NULL;\n\n\t\tbytes = iov_iter_count(i);\nretry:\n\t\toffset = pos & (chunk - 1);\n\t\tbytes = min(chunk - offset, bytes);\n\t\tbalance_dirty_pages_ratelimited(mapping);\n\n\t\tif (fatal_signal_pending(current)) {\n\t\t\tstatus = -EINTR;\n\t\t\tbreak;\n\t\t}\n\n\t\tstatus = a_ops->write_begin(iocb, mapping, pos, bytes,\n\t\t\t\t\t\t&folio, &fsdata);\n\t\tif (unlikely(status < 0))\n\t\t\tbreak;\n\n\t\toffset = offset_in_folio(folio, pos);\n\t\tif (bytes > folio_size(folio) - offset)\n\t\t\tbytes = folio_size(folio) - offset;\n\n\t\tif (mapping_writably_mapped(mapping))\n\t\t\tflush_dcache_folio(folio);\n\n\t\t/*\n\t\t * Faults here on mmap()s can recurse into arbitrary\n\t\t * filesystem code. Lots of locks are held that can\n\t\t * deadlock. Use an atomic copy to avoid deadlocking\n\t\t * in page fault handling.\n\t\t */\n\t\tcopied = copy_folio_from_iter_atomic(folio, offset, bytes, i);\n\t\tflush_dcache_folio(folio);\n\n\t\tstatus = a_ops->write_end(iocb, mapping, pos, bytes, copied,\n\t\t\t\t\t\tfolio, fsdata);\n\t\tif (unlikely(status != copied)) {\n\t\t\tiov_iter_revert(i, copied - max(status, 0L));\n\t\t\tif (unlikely(status < 0))\n\t\t\t\tbreak;\n\t\t}\n\t\tcond_resched();\n\n\t\tif (unlikely(status == 0)) {\n\t\t\t/*\n\t\t\t * A short copy made ->write_end() reject the\n\t\t\t * thing entirely.  Might be memory poisoning\n\t\t\t * halfway through, might be a race with munmap,\n\t\t\t * might be severe memory pressure.\n\t\t\t */\n\t\t\tif (chunk > PAGE_SIZE)\n\t\t\t\tchunk /= 2;\n\t\t\tif (copied) {\n\t\t\t\tbytes = copied;\n\t\t\t\tgoto retry;\n\t\t\t}\n\n\t\t\t/*\n\t\t\t * 'folio' is now unlocked and faults on it can be\n\t\t\t * handled. Ensure forward progress by trying to\n\t\t\t * fault it in now.\n\t\t\t */\n\t\t\tif (fault_in_iov_iter_readable(i, bytes) == bytes) {\n\t\t\t\tstatus = -EFAULT;\n\t\t\t\tbreak;\n\t\t\t}\n\t\t} else {\n\t\t\tpos += status;\n\t\t\twritten += status;\n\t\t}\n\t} while (iov_iter_count(i));\n\n\tif (!written)\n\t\treturn status;\n\tiocb->ki_pos += written;\n\treturn written;\n}\nEXPORT_SYMBOL(generic_perform_write);\n\n/**\n * __generic_file_write_iter - write data to a file\n * @iocb:\tIO state structure (file, offset, etc.)\n * @from:\tiov_iter with data to write\n *\n * This function does all the work needed for actually writing data to a\n * file. It does all basic checks, removes SUID from the file, updates\n * modification times and calls proper subroutines depending on whether we\n * do direct IO or a standard buffered write.\n *\n * It expects i_rwsem to be grabbed unless we work on a block device or similar\n * object which does not need locking at all.\n *\n * This function does *not* take care of syncing data in case of O_SYNC write.\n * A caller has to handle it. This is mainly due to the fact that we want to\n * avoid syncing under i_rwsem.\n *\n * Return:\n * * number of bytes written, even for truncated writes\n * * negative error code if no data has been written at all\n */\nssize_t __generic_file_write_iter(struct kiocb *iocb, struct iov_iter *from)\n{\n\tstruct file *file = iocb->ki_filp;\n\tstruct address_space *mapping = file->f_mapping;\n\tstruct inode *inode = mapping->host;\n\tssize_t ret;\n\n\tret = file_remove_privs(file);\n\tif (ret)\n\t\treturn ret;\n\n\tret = file_update_time(file);\n\tif (ret)\n\t\treturn ret;\n\n\tif (iocb->ki_flags & IOCB_DIRECT) {\n\t\tret = generic_file_direct_write(iocb, from);\n\t\t/*\n\t\t * If the write stopped short of completing, fall back to\n\t\t * buffered writes.  Some filesystems do this for writes to\n\t\t * holes, for example.  For DAX files, a buffered write will\n\t\t * not succeed (even if it did, DAX does not handle dirty\n\t\t * page-cache pages correctly).\n\t\t */\n\t\tif (ret < 0 || !iov_iter_count(from) || IS_DAX(inode))\n\t\t\treturn ret;\n\t\treturn direct_write_fallback(iocb, from, ret,\n\t\t\t\tgeneric_perform_write(iocb, from));\n\t}\n\n\treturn generic_perform_write(iocb, from);\n}\nEXPORT_SYMBOL(__generic_file_write_iter);\n\n/**\n * generic_file_write_iter - write data to a file\n * @iocb:\tIO state structure\n * @from:\tiov_iter with data to write\n *\n * This is a wrapper around __generic_file_write_iter() to be used by most\n * filesystems. It takes care of syncing the file in case of O_SYNC file\n * and acquires i_rwsem as needed.\n * Return:\n * * negative error code if no data has been written at all of\n *   vfs_fsync_range() failed for a synchronous write\n * * number of bytes written, even for truncated writes\n */\nssize_t generic_file_write_iter(struct kiocb *iocb, struct iov_iter *from)\n{\n\tstruct file *file = iocb->ki_filp;\n\tstruct inode *inode = file->f_mapping->host;\n\tssize_t ret;\n\n\tinode_lock(inode);\n\tret = generic_write_checks(iocb, from);\n\tif (ret > 0)\n\t\tret = __generic_file_write_iter(iocb, from);\n\tinode_unlock(inode);\n\n\tif (ret > 0)\n\t\tret = generic_write_sync(iocb, ret);\n\treturn ret;\n}\nEXPORT_SYMBOL(generic_file_write_iter);\n\n/**\n * filemap_release_folio() - Release fs-specific metadata on a folio.\n * @folio: The folio which the kernel is trying to free.\n * @gfp: Memory allocation flags (and I/O mode).\n *\n * The address_space is trying to release any data attached to a folio\n * (presumably at folio->private).\n *\n * This will also be called if the private_2 flag is set on a page,\n * indicating that the folio has other metadata associated with it.\n *\n * The @gfp argument specifies whether I/O may be performed to release\n * this page (__GFP_IO), and whether the call may block\n * (__GFP_RECLAIM & __GFP_FS).\n *\n * Return: %true if the release was successful, otherwise %false.\n */\nbool filemap_release_folio(struct folio *folio, gfp_t gfp)\n{\n\tstruct address_space * const mapping = folio->mapping;\n\n\tBUG_ON(!folio_test_locked(folio));\n\tif (!folio_needs_release(folio))\n\t\treturn true;\n\tif (folio_test_writeback(folio))\n\t\treturn false;\n\n\tif (mapping && mapping->a_ops->release_folio)\n\t\treturn mapping->a_ops->release_folio(folio, gfp);\n\treturn try_to_free_buffers(folio);\n}\nEXPORT_SYMBOL(filemap_release_folio);\n\n/**\n * filemap_invalidate_inode - Invalidate/forcibly write back a range of an inode's pagecache\n * @inode: The inode to flush\n * @flush: Set to write back rather than simply invalidate.\n * @start: First byte to in range.\n * @end: Last byte in range (inclusive), or LLONG_MAX for everything from start\n *       onwards.\n *\n * Invalid