    "content": "{"content":"// SPDX-License-Identifier: GPL-2.0-only\n/*\n *\tlinux/mm/filemap.c\n *\n * Copyright (C) 1994-1999  Linus Torvalds\n */\n\n/*\n * This file handles the generic file mmap semantics used by\n * most \"normal\" filesystems (but you don't /have/ to use this:\n * the NFS filesystem used to do this differently, for example)\n */\n#include <linux/export.h>\n#include <linux/compiler.h>\n#include <linux/dax.h>\n#include <linux/fs.h>\n#include <linux/sched/signal.h>\n#include <linux/uaccess.h>\n#include <linux/capability.h>\n#include <linux/kernel_stat.h>\n#include <linux/gfp.h>\n#include <linux/mm.h>\n#include <linux/swap.h>\n#include <linux/leafops.h>\n#include <linux/syscalls.h>\n#include <linux/mman.h>\n#include <linux/pagemap.h>\n#include <linux/file.h>\n#include <linux/uio.h>\n#include <linux/error-injection.h>\n#include <linux/hash.h>\n#include <linux/writeback.h>\n#include <linux/backing-dev.h>\n#include <linux/folio_batch.h>\n#include <linux/security.h>\n#include <linux/cpuset.h>\n#include <linux/hugetlb.h>\n#include <linux/memcontrol.h>\n#include <linux/shmem_fs.h>\n#include <linux/rmap.h>\n#include <linux/delayacct.h>\n#include <linux/psi.h>\n#include <linux/ramfs.h>\n#include <linux/page_idle.h>\n#include <linux/migrate.h>\n#include <linux/pipe_fs_i.h>\n#include <linux/splice.h>\n#include <linux/rcupdate_wait.h>\n#include <linux/sched/mm.h>\n#include <linux/sysctl.h>\n#include <linux/pgalloc.h>\n\n#include <asm/tlbflush.h>\n#include \"internal.h\"\n\n#define CREATE_TRACE_POINTS\n#include <trace/events/filemap.h>\n\n/*\n * FIXME: remove all knowledge of the buffer layer from the core VM\n */\n#include <linux/buffer_head.h> /* for try_to_free_buffers */\n\n#include <asm/mman.h>\n\n#include \"swap.h\"\n\n/*\n * Shared mappings implemented 30.11.1994. It's not fully working yet,\n * though.\n *\n * Shared mappings now work. 15.8.1995  Bruno.\n *\n * finished 'unifying' the page and buffer cache and SMP-threaded the\n * page-cache, 21.05.1999, Ingo Molnar <mingo@redhat.com>\n *\n * SMP-threaded pagemap-LRU 1999, Andrea Arcangeli <andrea@suse.de>\n */\n\n/*\n * Lock ordering:\n *\n *  ->i_mmap_rwsem\t\t(truncate_pagecache)\n *    ->private_lock\t\t(__free_pte->block_dirty_folio)\n *      ->swap_lock\t\t(exclusive_swap_page, others)\n *        ->i_pages lock\n *\n *  ->i_rwsem\n *    ->invalidate_lock\t\t(acquired by fs in truncate path)\n *      ->i_mmap_rwsem\t\t(truncate->unmap_mapping_range)\n *\n *  ->mmap_lock\n *    ->i_mmap_rwsem\n *      ->page_table_lock or pte_lock\t(various, mainly in memory.c)\n *        ->i_pages lock\t(arch-dependent flush_dcache_mmap_lock)\n *\n *  ->mmap_lock\n *    ->invalidate_lock\t\t(filemap_fault)\n *      ->lock_page\t\t(filemap_fault, access_process_vm)\n *\n *  ->i_rwsem\t\t\t(generic_perform_write)\n *    ->mmap_lock\t\t(fault_in_readable->do_page_fault)\n *\n *  bdi->wb.list_lock\n *    sb_lock\t\t\t(fs/fs-writeback.c)\n *    ->i_pages lock\t\t(__sync_single_inode)\n *\n *  ->i_mmap_rwsem\n *    ->anon_vma.lock\t\t(vma_merge)\n *\n *  ->anon_vma.lock\n *    ->page_table_lock or pte_lock\t(anon_vma_prepare and various)\n *\n *  ->page_table_lock or pte_lock\n *    ->swap_lock\t\t(try_to_unmap_one)\n *    ->private_lock\t\t(try_to_unmap_one)\n *    ->i_pages lock\t\t(try_to_unmap_one)\n *    ->lruvec->lru_lock\t(follow_page_mask->mark_page_accessed)\n *    ->lruvec->lru_lock\t(check_pte_range->folio_isolate_lru)\n *    ->private_lock\t\t(folio_remove_rmap_pte->set_page_dirty)\n *    ->i_pages lock\t\t(folio_remove_rmap_pte->set_page_dirty)\n *    bdi.wb->list_lock\t\t(folio_remove_rmap_pte->set_page_dirty)\n *    ->inode->i_lock\t\t(folio_remove_rmap_pte->set_page_dirty)\n *    bdi.wb->list_lock\t\t(zap_pte_range->set_page_dirty)\n *    ->inode->i_lock\t\t(zap_pte_range->set_page_dirty)\n *    ->private_lock\t\t(zap_pte_range->block_dirty_folio)\n */\n\nstatic void page_cache_delete(struct address_space *mapping,\n\t\t\t\t   struct folio *folio, void *shadow)\n{\n\tXA_STATE(xas, &mapping->i_pages, folio->index);\n\tlong nr = 1;\n\n\tmapping_set_update(&xas, mapping);\n\n\txas_set_order(&xas, folio->index, folio_order(folio));\n\tnr = folio_nr_pages(folio);\n\n\tVM_BUG_ON_FOLIO(!folio_test_locked(folio), folio);\n\n\txas_store(&xas, shadow);\n\txas_init_marks(&xas);\n\n\tfolio->mapping = NULL;\n\t/* Leave folio->index set: truncation lookup relies upon it */\n\tmapping->nrpages -= nr;\n}\n\nstatic void filemap_unaccount_folio(struct address_space *mapping,\n\t\tstruct folio *folio)\n{\n\tlong nr;\n\n\tVM_BUG_ON_FOLIO(folio_mapped(folio), folio);\n\tif (!IS_ENABLED(CONFIG_DEBUG_VM) && unlikely(folio_mapped(folio))) {\n\t\tpr_alert(\"BUG: Bad page cache in process %s  pfn:%05lx\\n\",\n\t\t\t current->comm, folio_pfn(folio));\n\t\tdump_page(&folio->page, \"still mapped when deleted\");\n\t\tdump_stack();\n\t\tadd_taint(TAINT_BAD_PAGE, LOCKDEP_NOW_UNRELIABLE);\n\n\t\tif (mapping_exiting(mapping) && !folio_test_large(folio)) {\n\t\t\tint mapcount = folio_mapcount(folio);\n\n\t\t\tif (folio_ref_count(folio) >= mapcount + 2) {\n\t\t\t\t/*\n\t\t\t\t * All vmas have already been torn down, so it's\n\t\t\t\t * a good bet that actually the page is unmapped\n\t\t\t\t * and we'd rather not leak it: if we're wrong,\n\t\t\t\t * another bad page check should catch it later.\n\t\t\t\t */\n\t\t\t\tatomic_set(&folio->_mapcount, -1);\n\t\t\t\tfolio_ref_sub(folio, mapcount);\n\t\t\t}\n\t\t}\n\t}\n\n\t/* hugetlb folios do not participate in page cache accounting. */\n\tif (folio_test_hugetlb(folio))\n\t\treturn;\n\n\tnr = folio_nr_pages(folio);\n\n\tlruvec_stat_mod_folio(folio, NR_FILE_PAGES, -nr);\n\tif (folio_test_swapbacked(folio)) {\n\t\tlruvec_stat_mod_folio(folio, NR_SHMEM, -nr);\n\t\tif (folio_test_pmd_mappable(folio))\n\t\t\tlruvec_stat_mod_folio(folio, NR_SHMEM_THPS, -nr);\n\t} else if (folio_test_pmd_mappable(folio)) {\n\t\tlruvec_stat_mod_folio(folio, NR_FILE_THPS, -nr);\n\t\tfilemap_nr_thps_dec(mapping);\n\t}\n\tif (test_bit(AS_KERNEL_FILE, &folio->mapping->flags))\n\t\tmod_node_page_state(folio_pgdat(folio),\n\t\t\t\t    NR_KERNEL_FILE_PAGES, -nr);\n\n\t/*\n\t * At this point folio must be either written or cleaned by\n\t * truncate.  Dirty folio here signals a bug and loss of\n\t * unwritten data - on ordinary filesystems.\n\t *\n\t * But it's harmless on in-memory filesystems like tmpfs; and can\n\t * occur when a driver which did get_user_pages() sets page dirty\n\t * before putting it, while the inode is being finally evicted.\n\t *\n\t * Below fixes dirty accounting after removing the folio entirely\n\t * but leaves the dirty flag set: it has no effect for truncated\n\t * folio and anyway will be cleared before returning folio to\n\t * buddy allocator.\n\t */\n\tif (WARN_ON_ONCE(folio_test_dirty(folio) &&\n\t\t\t mapping_can_writeback(mapping)))\n\t\tfolio_account_cleaned(folio, inode_to_wb(mapping->host));\n}\n\n/*\n * Delete a page from the page cache and free it. Caller has to make\n * sure the page is locked and that nobody else uses it - or that usage\n * is safe.  The caller must hold the i_pages lock.\n */\nvoid __filemap_remove_folio(struct folio *folio, void *shadow)\n{\n\tstruct address_space *mapping = folio->mapping;\n\n\ttrace_mm_filemap_delete_from_page_cache(folio);\n\tfilemap_unaccount_folio(mapping, folio);\n\tpage_cache_delete(mapping, folio, shadow);\n}\n\nvoid filemap_free_folio(struct address_space *mapping, struct folio *folio)\n{\n\tvoid (*free_folio)(struct folio *);\n\n\tfree_folio = mapping->a_ops->free_folio;\n\tif (free_folio)\n\t\tfree_folio(folio);\n\n\tfolio_put_refs(folio, folio_nr_pages(folio));\n}\n\n/**\n * filemap_remove_folio - Remove folio from page cache.\n * @folio: The folio.\n *\n * This must be called only on folios that are locked and have been\n * verified to be in the page cache.  It will never put the folio into\n * the free list because the caller has a reference on the page.\n */\nvoid filemap_remove_folio(struct folio *folio)\n{\n\tstruct address_space *mapping = folio->mapping;\n\n\tBUG_ON(!folio_test_locked(folio));\n\tspin_lock(&mapping->host->i_lock);\n\txa_lock_irq(&mapping->i_pages);\n\t__filemap_remove_folio(folio, NULL);\n\txa_unlock_irq(&mapping->i_pages);\n\tif (mapping_shrinkable(mapping))\n\t\tinode_lru_list_add(mapping->host);\n\tspin_unlock(&mapping->host->i_lock);\n\n\tfilemap_free_folio(mapping, folio);\n}\nEXPORT_SYMBOL_FOR_MODULES(filemap_remove_folio, \"kvm\");\n\n/*\n * page_cache_delete_batch - delete several folios from page cache\n * @mapping: the mapping to which folios belong\n * @fbatch: batch of folios to delete\n *\n * The function walks over mapping->i_pages and removes folios passed in\n * @fbatch from the mapping. The function expects @fbatch to be sorted\n * by page index and is optimised for it to be dense.\n * It tolerates holes in @fbatch (mapping entries at those indices are not\n * modified).\n *\n * The function expects the i_pages lock to be held.\n */\nstatic void page_cache_delete_batch(struct address_space *mapping,\n\t\t\t     struct folio_batch *fbatch)\n{\n\tXA_STATE(xas, &mapping->i_pages, fbatch->folios[0]->index);\n\tlong total_pages = 0;\n\tint i = 0;\n\tstruct folio *folio;\n\n\tmapping_set_update(&xas, mapping);\n\txas_for_each(&xas, folio, ULONG_MAX) {\n\t\tif (i >= folio_batch_count(fbatch))\n\t\t\tbreak;\n\n\t\t/* A swap/dax/shadow entry got inserted? Skip it. */\n\t\tif (xa_is_value(folio))\n\t\t\tcontinue;\n\t\t/*\n\t\t * A page got inserted in our range? Skip it. We have our\n\t\t * pages locked so they are protected from being removed.\n\t\t * If we see a page whose index is higher than ours, it\n\t\t * means our page has been removed, which shouldn't be\n\t\t * possible because we're holding the PageLock.\n\t\t */\n\t\tif (folio != fbatch->folios[i]) {\n\t\t\tVM_BUG_ON_FOLIO(folio->index >\n\t\t\t\t\tfbatch->folios[i]->index, folio);\n\t\t\tcontinue;\n\t\t}\n\n\t\tWARN_ON_ONCE(!folio_test_locked(folio));\n\n\t\tfolio->mapping = NULL;\n\t\t/* Leave folio->index set: truncation lookup relies on it */\n\n\t\ti++;\n\t\txas_store(&xas, NULL);\n\t\ttotal_pages += folio_nr_pages(folio);\n\t}\n\tmapping->nrpages -= total_pages;\n}\n\nvoid delete_from_page_cache_batch(struct address_space *mapping,\n\t\t\t\t  struct folio_batch *fbatch)\n{\n\tint i;\n\n\tif (!folio_batch_count(fbatch))\n\t\treturn;\n\n\tspin_lock(&mapping->host->i_lock);\n\txa_lock_irq(&mapping->i_pages);\n\tfor (i = 0; i < folio_batch_count(fbatch); i++) {\n\t\tstruct folio *folio = fbatch->folios[i];\n\n\t\ttrace_mm_filemap_delete_from_page_cache(folio);\n\t\tfilemap_unaccount_folio(mapping, folio);\n\t}\n\tpage_cache_delete_batch(mapping, fbatch);\n\txa_unlock_irq(&mapping->i_pages);\n\tif (mapping_shrinkable(mapping))\n\t\tinode_lru_list_add(mapping->host);\n\tspin_unlock(&mapping->host->i_lock);\n\n\tfor (i = 0; i < folio_batch_count(fbatch); i++)\n\t\tfilemap_free_folio(mapping, fbatch->folios[i]);\n}\n\nint filemap_check_errors(struct address_space *mapping)\n{\n\tint ret = 0;\n\t/* Check for outstanding write errors */\n\tif (test_bit(AS_ENOSPC, &mapping->flags) &&\n\t    test_and_clear_bit(AS_ENOSPC, &mapping->flags))\n\t\tret = -ENOSPC;\n\tif (test_bit(AS_EIO, &mapping->flags) &&\n\t    test_and_clear_bit(AS_EIO, &mapping->flags))\n\t\tret = -EIO;\n\treturn ret;\n}\nEXPORT_SYMBOL(filemap_check_errors);\n\nstatic int filemap_check_and_keep_errors(struct address_space *mapping)\n{\n\t/* Check for outstanding write errors */\n\tif (test_bit(AS_EIO, &mapping->flags))\n\t\treturn -EIO;\n\tif (test_bit(AS_ENOSPC, &mapping->flags))\n\t\treturn -ENOSPC;\n\treturn 0;\n}\n\nstatic int filemap_writeback(struct address_space *mapping, loff_t start,\n\t\tloff_t end, enum writeback_sync_modes sync_mode,\n\t\tlong *nr_to_write)\n{\n\tstruct writeback_control wbc = {\n\t\t.sync_mode\t= sync_mode,\n\t\t.nr_to_write\t= nr_to_write ? *nr_to_write : LONG_MAX,\n\t\t.range_start\t= start,\n\t\t.range_end\t= end,\n\t};\n\tint ret;\n\n\tif (!mapping_can_writeback(mapping) ||\n\t    !mapping_tagged(mapping, PAGECACHE_TAG_DIRTY))\n\t\treturn 0;\n\n\twbc_attach_fdatawrite_inode(&wbc, mapping->host);\n\tret = do_writepages(mapping, &wbc);\n\twbc_detach_inode(&wbc);\n\n\tif (!ret && nr_to_write)\n\t\t*nr_to_write = wbc.nr_to_write;\n\treturn ret;\n}\n\n/**\n * filemap_fdatawrite_range - start writeback on mapping dirty pages in range\n * @mapping:\taddress space structure to write\n * @start:\toffset in bytes where the range starts\n * @end:\toffset in bytes where the range ends (inclusive)\n\n... [Diff truncated. Dropped 3952 lines] ...\n\n\t\tcond_resched();\n\n\t\tif (unlikely(status == 0)) {\n\t\t\t/*\n\t\t\t * A short copy made ->write_end() reject the\n\t\t\t * thing entirely.  Might be memory poisoning\n\t\t\t * halfway through, might be a race with munmap,\n\t\t\t * might be severe memory pressure.\n\t\t\t */\n\t\t\tif (chunk > PAGE_SIZE)\n\t\t\t\tchunk /= 2;\n\t\t\tif (copied) {\n\t\t\t\tbytes = copied;\n\t\t\t\tgoto retry;\n\t\t\t}\n\n\t\t\t/*\n\t\t\t * 'folio' is now unlocked and faults on it can be\n\t\t\t * handled. Ensure forward progress by trying to\n\t\t\t * fault it in now.\n\t\t\t */\n\t\t\tif (fault_in_iov_iter_readable(i, bytes) == bytes) {\n\t\t\t\tstatus = -EFAULT;\n\t\t\t\tbreak;\n\t\t\t}\n\t\t} else {\n\t\t\tpos += status;\n\t\t\twritten += status;\n\t\t}\n\t} while (iov_iter_count(i));\n\n\tif (!written)\n\t\treturn status;\n\tiocb->ki_pos += written;\n\treturn written;\n}\nEXPORT_SYMBOL(generic_perform_write);\n\n/**\n * __generic_file_write_iter - write data to a file\n * @iocb:\tIO state structure (file, offset, etc.)\n * @from:\tiov_iter with data to write\n *\n * This function does all the work needed for actually writing data to a\n * file. It does all basic checks, removes SUID from the file, updates\n * modification times and calls proper subroutines depending on whether we\n * do direct IO or a standard buffered write.\n *\n * It expects i_rwsem to be grabbed unless we work on a block device or similar\n * object which does not need locking at all.\n *\n * This function does *not* take care of syncing data in case of O_SYNC write.\n * A caller has to handle it. This is mainly due to the fact that we want to\n * avoid syncing under i_rwsem.\n *\n * Return:\n * * number of bytes written, even for truncated writes\n * * negative error code if no data has been written at all\n */\nssize_t __generic_file_write_iter(struct kiocb *iocb, struct iov_iter *from)\n{\n\tstruct file *file = iocb->ki_filp;\n\tstruct address_space *mapping = file->f_mapping;\n\tstruct inode *inode = mapping->host;\n\tssize_t ret;\n\n\tret = file_remove_privs(file);\n\tif (ret)\n\t\treturn ret;\n\n\tret = file_update_time(file);\n\tif (ret)\n\t\treturn ret;\n\n\tif (iocb->ki_flags & IOCB_DIRECT) {\n\t\tret = generic_file_direct_write(iocb, from);\n\t\t/*\n\t\t * If the write stopped short of completing, fall back to\n\t\t * buffered writes.  Some filesystems do this for writes to\n\t\t * holes, for example.  For DAX files, a buffered write will\n\t\t * not succeed (even if it did, DAX does not handle dirty\n\t\t * page-cache pages correctly).\n\t\t */\n\t\tif (ret < 0 || !iov_iter_count(from) || IS_DAX(inode))\n\t\t\treturn ret;\n\t\treturn direct_write_fallback(iocb, from, ret,\n\t\t\t\tgeneric_perform_write(iocb, from));\n\t}\n\n\treturn generic_perform_write(iocb, from);\n}\nEXPORT_SYMBOL(__generic_file_write_iter);\n\n/**\n * generic_file_write_iter - write data to a file\n * @iocb:\tIO state structure\n * @from:\tiov_iter with data to write\n *\n * This is a wrapper around __generic_file_write_iter() to be used by most\n * filesystems. It takes care of syncing the file in case of O_SYNC file\n * and acquires i_rwsem as needed.\n * Return:\n * * negative error code if no data has been written at all of\n *   vfs_fsync_range() failed for a synchronous write\n * * number of bytes written, even for truncated writes\n */\nssize_t generic_file_write_iter(struct kiocb *iocb, struct iov_iter *from)\n{\n\tstruct file *file = iocb->ki_filp;\n\tstruct inode *inode = file->f_mapping->host;\n\tssize_t ret;\n\n\tinode_lock(inode);\n\tret = generic_write_checks(iocb, from);\n\tif (ret > 0)\n\t\tret = __generic_file_write_iter(iocb, from);\n\tinode_unlock(inode);\n\n\tif (ret > 0)\n\t\tret = generic_write_sync(iocb, ret);\n\treturn ret;\n}\nEXPORT_SYMBOL(generic_file_write_iter);\n\n/**\n * filemap_release_folio() - Release fs-specific metadata on a folio.\n * @folio: The folio which the kernel is trying to free.\n * @gfp: Memory allocation flags (and I/O mode).\n *\n * The address_space is trying to release any data attached to a folio\n * (presumably at folio->private).\n *\n * This will also be called if the private_2 flag is set on a page,\n * indicating that the folio has other metadata associated with it.\n *\n * The @gfp argument specifies whether I/O may be performed to release\n * this page (__GFP_IO), and whether the call may block\n * (__GFP_RECLAIM & __GFP_FS).\n *\n * Return: %true if the release was successful, otherwise %false.\n */\nbool filemap_release_folio(struct folio *folio, gfp_t gfp)\n{\n\tstruct address_space * const mapping = folio->mapping;\n\n\tBUG_ON(!folio_test_locked(folio));\n\tif (!folio_needs_release(folio))\n\t\treturn true;\n\tif (folio_test_writeback(folio))\n\t\treturn false;\n\n\tif (mapping && mapping->a_ops->release_folio)\n\t\treturn mapping->a_ops->release_folio(folio, gfp);\n\treturn try_to_free_buffers(folio);\n}\nEXPORT_SYMBOL(filemap_release_folio);\n\n/**\n * filemap_invalidate_inode - Invalidate/forcibly write back a range of an inode's pagecache\n * @inode: The inode to flush\n * @flush: Set to write back rather than simply invalidate.\n * @start: First byte to in range.\n * @end: Last byte in range (inclusive), or LLONG_MAX for everything from start\n *       onwards.\n *\n * Invalidate all the folios on an inode that contribute to the specified\n * range, possibly writing them back first.  Whilst the operation is\n * undertaken, the invalidate lock is held to prevent new folios from being\n * installed.\n */\nint filemap_invalidate_inode(struct inode *inode, bool flush,\n\t\t\t     loff_t start, loff_t end)\n{\n\tstruct address_space *mapping = inode->i_mapping;\n\tpgoff_t first = start >> PAGE_SHIFT;\n\tpgoff_t last = end >> PAGE_SHIFT;\n\tpgoff_t nr = end == LLONG_MAX ? ULONG_MAX : last - first + 1;\n\n\tif (!mapping || !mapping->nrpages || end < start)\n\t\tgoto out;\n\n\t/* Prevent new folios from being added to the inode. */\n\tfilemap_invalidate_lock(mapping);\n\n\tif (!mapping->nrpages)\n\t\tgoto unlock;\n\n\tunmap_mapping_pages(mapping, first, nr, false);\n\n\t/* Write back the data if we're asked to. */\n\tif (flush)\n\t\tfilemap_fdatawrite_range(mapping, start, end);\n\n\t/* Wait for writeback to complete on all folios and discard. */\n\tinvalidate_inode_pages2_range(mapping, start / PAGE_SIZE, end / PAGE_SIZE);\n\nunlock:\n\tfilemap_invalidate_unlock(mapping);\nout:\n\treturn filemap_check_errors(mapping);\n}\nEXPORT_SYMBOL_GPL(filemap_invalidate_inode);\n\n#ifdef CONFIG_CACHESTAT_SYSCALL\n/**\n * filemap_cachestat() - compute the page cache statistics of a mapping\n * @mapping:\tThe mapping to compute the statistics for.\n * @first_index:\tThe starting page cache index.\n * @last_index:\tThe final page index (inclusive).\n * @cs:\tthe cachestat struct to write the result to.\n *\n * This will query the page cache statistics of a mapping in the\n * page range of [first_index, last_index] (inclusive). The statistics\n * queried include: number of dirty pages, number of pages marked for\n * writeback, and the number of (recently) evicted pages.\n */\nstatic void filemap_cachestat(struct address_space *mapping,\n\t\tpgoff_t first_index, pgoff_t last_index, struct cachestat *cs)\n{\n\tXA_STATE(xas, &mapping->i_pages, first_index);\n\tstruct folio *folio;\n\n\t/* Flush stats (and potentially sleep) outside the RCU read section. */\n\tmem_cgroup_flush_stats_ra